1	use alloc::{boxed::Box, vec::Vec};
2	use core::{
3	    cell::UnsafeCell,
4	    fmt,
5	    marker::PhantomData,
6	    mem,
7	    ops::{Deref, DerefMut},
8	    panic::{RefUnwindSafe, UnwindSafe},
9	};
10	use std::{
11	    collections::HashMap,
12	    sync::{
13	        LockResult, Mutex, PoisonError, RwLock, RwLockReadGuard, RwLockWriteGuard, TryLockError,
14	        TryLockResult,
15	    },
16	    thread::{self, ThreadId},
17	};
18	
19	use crate::{CachePadded, sync::once_lock::OnceLock};
20	
21	/// The number of shards per sharded lock. Must be a power of two.
22	const NUM_SHARDS: usize = 8;
23	
24	/// A shard containing a single reader-writer lock.
25	struct Shard {
26	    /// The inner reader-writer lock.
27	    lock: RwLock<()>,
28	
29	    /// The write-guard keeping this shard locked.
30	    ///
31	    /// Write operations will lock each shard and store the guard here. These guards get dropped at
32	    /// the same time the big guard is dropped.
33	    write_guard: UnsafeCell<Option<RwLockWriteGuard<'static, ()>>>,
34	}
35	
36	/// A sharded reader-writer lock.
37	///
38	/// This lock is equivalent to [`RwLock`], except read operations are faster and write operations
39	/// are slower.
40	///
41	/// A `ShardedLock` is internally made of a list of *shards*, each being a [`RwLock`] occupying a
42	/// single cache line. Read operations will pick one of the shards depending on the current thread
43	/// and lock it. Write operations need to lock all shards in succession.
44	///
45	/// By splitting the lock into shards, concurrent read operations will in most cases choose
46	/// different shards and thus update different cache lines, which is good for scalability. However,
47	/// write operations need to do more work and are therefore slower than usual.
48	///
49	/// The priority policy of the lock is dependent on the underlying operating system's
50	/// implementation, and this type does not guarantee that any particular policy will be used.
51	///
52	/// # Poisoning
53	///
54	/// A `ShardedLock`, like [`RwLock`], will become poisoned on a panic. Note that it may only be
55	/// poisoned if a panic occurs while a write operation is in progress. If a panic occurs in any
56	/// read operation, the lock will not be poisoned.
57	///
58	/// # Examples
59	///
60	/// ```
61	/// use crossbeam_utils::sync::ShardedLock;
62	///
63	/// let lock = ShardedLock::new(5);
64	///
65	/// // Any number of read locks can be held at once.
66	/// {
67	///     let r1 = lock.read().unwrap();
68	///     let r2 = lock.read().unwrap();
69	///     assert_eq!(*r1, 5);
70	///     assert_eq!(*r2, 5);
71	/// } // Read locks are dropped at this point.
72	///
73	/// // However, only one write lock may be held.
74	/// {
75	///     let mut w = lock.write().unwrap();
76	///     *w += 1;
77	///     assert_eq!(*w, 6);
78	/// } // Write lock is dropped here.
79	/// ```
80	///
81	/// [`RwLock`]: std::sync::RwLock
82	pub struct ShardedLock<T: ?Sized> {
83	    /// A list of locks protecting the internal data.
84	    shards: Box<[CachePadded<Shard>]>,
85	
86	    /// The internal data.
87	    value: UnsafeCell<T>,
88	}
89	
90	unsafe impl<T: ?Sized + Send> Send for ShardedLock<T> {}
91	unsafe impl<T: ?Sized + Send + Sync> Sync for ShardedLock<T> {}
92	
93	impl<T: ?Sized> UnwindSafe for ShardedLock<T> {}
94	impl<T: ?Sized> RefUnwindSafe for ShardedLock<T> {}
95	
96	impl<T> ShardedLock<T> {
97	    /// Creates a new sharded reader-writer lock.
98	    ///
99	    /// # Examples
100	    ///
101	    /// ```
102	    /// use crossbeam_utils::sync::ShardedLock;
103	    ///
104	    /// let lock = ShardedLock::new(5);
105	    /// ```
106	    pub fn new(value: T) -> Self {
107	        Self {
108	            shards: (0..NUM_SHARDS)
109	                .map(|_| {
110	                    CachePadded::new(Shard {
111	                        lock: RwLock::new(()),
112	                        write_guard: UnsafeCell::new(None),
113	                    })
114	                })
115	                .collect::<Box<[_]>>(),
116	            value: UnsafeCell::new(value),
117	        }
118	    }
119	
120	    /// Consumes this lock, returning the underlying data.
121	    ///
122	    /// # Errors
123	    ///
124	    /// This method will return an error if the lock is poisoned. A lock gets poisoned when a write
125	    /// operation panics.
126	    ///
127	    /// # Examples
128	    ///
129	    /// ```
130	    /// use crossbeam_utils::sync::ShardedLock;
131	    ///
132	    /// let lock = ShardedLock::new(String::new());
133	    /// {
134	    ///     let mut s = lock.write().unwrap();
135	    ///     *s = "modified".to_owned();
136	    /// }
137	    /// assert_eq!(lock.into_inner().unwrap(), "modified");
138	    /// ```
139	    pub fn into_inner(self) -> LockResult<T> {
140	        let is_poisoned = self.is_poisoned();
141	        let inner = self.value.into_inner();
142	
143	        if is_poisoned {
144	            Err(PoisonError::new(inner))
145	        } else {
146	            Ok(inner)
147	        }
148	    }
149	}
150	
151	impl<T: ?Sized> ShardedLock<T> {
152	    /// Returns `true` if the lock is poisoned.
153	    ///
154	    /// If another thread can still access the lock, it may become poisoned at any time. A `false`
155	    /// result should not be trusted without additional synchronization.
156	    ///
157	    /// # Examples
158	    ///
159	    /// ```
160	    /// use crossbeam_utils::sync::ShardedLock;
161	    /// use std::sync::Arc;
162	    /// use std::thread;
163	    ///
164	    /// let lock = Arc::new(ShardedLock::new(0));
165	    /// let c_lock = lock.clone();
166	    ///
167	    /// let _: Result<(), _> = thread::spawn(move || {
168	    ///     let _lock = c_lock.write().unwrap();
169	    ///     panic!(); // the lock gets poisoned
170	    /// }).join();
171	    /// assert_eq!(lock.is_poisoned(), true);
172	    /// ```
173	    pub fn is_poisoned(&self) -> bool {
174	        self.shards[0].lock.is_poisoned()
175	    }
176	
177	    /// Returns a mutable reference to the underlying data.
178	    ///
179	    /// Since this call borrows the lock mutably, no actual locking needs to take place.
180	    ///
181	    /// # Errors
182	    ///
183	    /// This method will return an error if the lock is poisoned. A lock gets poisoned when a write
184	    /// operation panics.
185	    ///
186	    /// # Examples
187	    ///
188	    /// ```
189	    /// use crossbeam_utils::sync::ShardedLock;
190	    ///
191	    /// let mut lock = ShardedLock::new(0);
192	    /// *lock.get_mut().unwrap() = 10;
193	    /// assert_eq!(*lock.read().unwrap(), 10);
194	    /// ```
195	    pub fn get_mut(&mut self) -> LockResult<&mut T> {
196	        let is_poisoned = self.is_poisoned();
197	        let inner = unsafe { &mut *self.value.get() };
198	
199	        if is_poisoned {
200	            Err(PoisonError::new(inner))
201	        } else {
202	            Ok(inner)
203	        }
204	    }
205	
206	    /// Attempts to acquire this lock with shared read access.
207	    ///
208	    /// If the access could not be granted at this time, an error is returned. Otherwise, a guard
209	    /// is returned which will release the shared access when it is dropped. This method does not
210	    /// provide any guarantees with respect to the ordering of whether contentious readers or
211	    /// writers will acquire the lock first.
212	    ///
213	    /// # Errors
214	    ///
215	    /// This method will return an error if the lock is poisoned. A lock gets poisoned when a write
216	    /// operation panics.
217	    ///
218	    /// # Examples
219	    ///
220	    /// ```
221	    /// use crossbeam_utils::sync::ShardedLock;
222	    ///
223	    /// let lock = ShardedLock::new(1);
224	    ///
225	    /// match lock.try_read() {
226	    ///     Ok(n) => assert_eq!(*n, 1),
227	    ///     Err(_) => unreachable!(),
228	    /// };
229	    /// ```
230	    pub fn try_read(&self) -> TryLockResult<ShardedLockReadGuard<'_, T>> {
231	        // Take the current thread index and map it to a shard index. Thread indices will tend to
232	        // distribute shards among threads equally, thus reducing contention due to read-locking.
233	        let current_index = current_index().unwrap_or(0);
234	        let shard_index = current_index & (self.shards.len() - 1);
235	
236	        match self.shards[shard_index].lock.try_read() {
237	            Ok(guard) => Ok(ShardedLockReadGuard {
238	                lock: self,
239	                _guard: guard,
240	                _marker: PhantomData,
241	            }),
242	            Err(TryLockError::Poisoned(err)) => {
243	                let guard = ShardedLockReadGuard {
244	                    lock: self,
245	                    _guard: err.into_inner(),
246	                    _marker: PhantomData,
247	                };
248	                Err(TryLockError::Poisoned(PoisonError::new(guard)))
249	            }
250	            Err(TryLockError::WouldBlock) => Err(TryLockError::WouldBlock),
251	        }
252	    }
253	
254	    /// Locks with shared read access, blocking the current thread until it can be acquired.
255	    ///
256	    /// The calling thread will be blocked until there are no more writers which hold the lock.
257	    /// There may be other readers currently inside the lock when this method returns. This method
258	    /// does not provide any guarantees with respect to the ordering of whether contentious readers
259	    /// or writers will acquire the lock first.
260	    ///
261	    /// Returns a guard which will release the shared access when dropped.
262	    ///
263	    /// # Errors
264	    ///
265	    /// This method will return an error if the lock is poisoned. A lock gets poisoned when a write
266	    /// operation panics.
267	    ///
268	    /// # Panics
269	    ///
270	    /// This method might panic when called if the lock is already held by the current thread.
271	    ///
272	    /// # Examples
273	    ///
274	    /// ```
275	    /// use crossbeam_utils::sync::ShardedLock;
276	    /// use std::sync::Arc;
277	    /// use std::thread;
278	    ///
279	    /// let lock = Arc::new(ShardedLock::new(1));
280	    /// let c_lock = lock.clone();
281	    ///
282	    /// let n = lock.read().unwrap();
283	    /// assert_eq!(*n, 1);
284	    ///
285	    /// thread::spawn(move || {
286	    ///     let r = c_lock.read();
287	    ///     assert!(r.is_ok());
288	    /// }).join().unwrap();
289	    /// ```
290	    pub fn read(&self) -> LockResult<ShardedLockReadGuard<'_, T>> {
291	        // Take the current thread index and map it to a shard index. Thread indices will tend to
292	        // distribute shards among threads equally, thus reducing contention due to read-locking.
293	        let current_index = current_index().unwrap_or(0);
294	        let shard_index = current_index & (self.shards.len() - 1);
295	
296	        match self.shards[shard_index].lock.read() {
297	            Ok(guard) => Ok(ShardedLockReadGuard {
298	                lock: self,
299	                _guard: guard,
300	                _marker: PhantomData,
301	            }),
302	            Err(err) => Err(PoisonError::new(ShardedLockReadGuard {
303	                lock: self,
304	                _guard: err.into_inner(),
305	                _marker: PhantomData,
306	            })),
307	        }
308	    }
309	
310	    /// Attempts to acquire this lock with exclusive write access.
311	    ///
312	    /// If the access could not be granted at this time, an error is returned. Otherwise, a guard
313	    /// is returned which will release the exclusive access when it is dropped. This method does
314	    /// not provide any guarantees with respect to the ordering of whether contentious readers or
315	    /// writers will acquire the lock first.
316	    ///
317	    /// # Errors
318	    ///
319	    /// This method will return an error if the lock is poisoned. A lock gets poisoned when a write
320	    /// operation panics.
321	    ///
322	    /// # Examples
323	    ///
324	    /// ```
325	    /// use crossbeam_utils::sync::ShardedLock;
326	    ///
327	    /// let lock = ShardedLock::new(1);
328	    ///
329	    /// let n = lock.read().unwrap();
330	    /// assert_eq!(*n, 1);
331	    ///
332	    /// assert!(lock.try_write().is_err());
333	    /// ```
334	    pub fn try_write(&self) -> TryLockResult<ShardedLockWriteGuard<'_, T>> {
335	        let mut poisoned = false;
336	        let mut blocked = None;
337	
338	        // Write-lock each shard in succession.
339	        for (i, shard) in self.shards.iter().enumerate() {
340	            let guard = match shard.lock.try_write() {
341	                Ok(guard) => guard,
342	                Err(TryLockError::Poisoned(err)) => {
343	                    poisoned = true;
344	                    err.into_inner()
345	                }
346	                Err(TryLockError::WouldBlock) => {
347	                    blocked = Some(i);
348	                    break;
349	                }
350	            };
351	
352	            // Store the guard into the shard.
353	            unsafe {
354	                let guard: RwLockWriteGuard<'static, ()> = mem::transmute(guard);
355	                let dest: *mut _ = shard.write_guard.get();
356	                *dest = Some(guard);
357	            }
358	        }
359	
360	        if let Some(i) = blocked {
361	            // Unlock the shards in reverse order of locking.
362	            for shard in self.shards[0..i].iter().rev() {
363	                unsafe {
364	                    let dest: *mut _ = shard.write_guard.get();
365	                    let guard = (*dest).take();
366	                    drop(guard);
367	                }
368	            }
369	            Err(TryLockError::WouldBlock)
370	        } else if poisoned {
371	            let guard = ShardedLockWriteGuard {
372	                lock: self,
373	                _marker: PhantomData,
374	            };
375	            Err(TryLockError::Poisoned(PoisonError::new(guard)))
376	        } else {
377	            Ok(ShardedLockWriteGuard {
378	                lock: self,
379	                _marker: PhantomData,
380	            })
381	        }
382	    }
383	
384	    /// Locks with exclusive write access, blocking the current thread until it can be acquired.
385	    ///
386	    /// The calling thread will be blocked until there are no more writers which hold the lock.
387	    /// There may be other readers currently inside the lock when this method returns. This method
